parameters.jsCode:
const metrics = $input.first().json;
const anomalies = [];

// Revenue anomaly detection (>20% change)
if (Math.abs(metrics.revenue_change_pct) > 20) {
  anomalies.push({
    type: 'revenue',
    severity: Math.abs(metrics.revenue_change_pct) > 40 ? 'critical' : 'warning',
    metric: 'Daily Revenue',
    current: metrics.revenue_today,
    average: metrics.avg_revenue_7d,
    change_pct: metrics.revenue_change_pct,
    message: `Revenue ${metrics.revenue_change_pct > 0 ? 'increased' : 'decreased'} by ${Math.abs(metrics.revenue_change_pct)}%`
  });
}

// Support ticket spike detection (>30% increase)
if (metrics.tickets_change_pct > 30) {
  anomalies.push({
    type: 'support',
    severity: metrics.tickets_change_pct > 50 ? 'critical' : 'warning',
    metric: 'Support Tickets',
    current: metrics.support_tickets_today,
    average: metrics.avg_tickets_7d,
    change_pct: metrics.tickets_change_pct,
    message: `Support tickets increased by ${metrics.tickets_change_pct}%`
  });
}

// High priority ticket alert
if (metrics.high_priority_tickets > 5) {
  anomalies.push({
    type: 'support',
    severity: 'warning',
    metric: 'High Priority Tickets',
    current: metrics.high_priority_tickets,
    message: `${metrics.high_priority_tickets} high priority tickets need attention`
  });
}

// Low resolution rate
if (metrics.ticket_resolution_rate < 70) {
  anomalies.push({
    type: 'support',
    severity: 'warning',
    metric: 'Ticket Resolution Rate',
    current: metrics.ticket_resolution_rate,
    message: `Resolution rate dropped to ${metrics.ticket_resolution_rate}%`
  });
}

return anomalies.length > 0 
  ? anomalies.map(a => ({ json: { ...metrics, anomaly: a, has_anomalies: true } }))
  : [{ json: { ...metrics, has_anomalies: false } }];

